    uart_putchar(10);

    sym_exit_scope();
    idx = sym_lookup("B");
    uart_putstr("lookup B after exit: ");
    print_int(idx);
    uart_putchar(10);

    idx = sym_lookup("A");
    uart_putstr("lookup A after exit: ");
    print_int(idx);
    uart_putchar(10);

    sym_exit_scope();

    /* Test 12: dump all scopes */
    uart_puts("--- dump all ---");
    sym_dump_all();

    /* Test 13: procedure symbol */
    uart_puts("--- proc symbol ---");
    idx = sym_insert("MAIN", TYPE_NONE, 0, STOR_AUTO);
